// Build lookup maps for efficient access
export const CITIES_BY_STATE: Record<string, CityData[]> = {};
export const CITY_BY_SLUG: Record<string, CityData> = {};

for (const city of CITIES) {
  const key = `${city.stateSlug}/${city.slug}`;
  CITY_BY_SLUG[key] = city;

  if (!CITIES_BY_STATE[city.stateSlug]) {
    CITIES_BY_STATE[city.stateSlug] = [];
  }
  CITIES_BY_STATE[city.stateSlug].push(city);
}

// All unique state slugs that have cities
export const STATES_WITH_CITIES = [...new Set(CITIES.map((c) => c.stateSlug))].sort();
